INSERT INTO ui_translations (key, locale, value) VALUES
  ('nav.memory_book', 'fr', 'Pourquoi votre famille a besoin d''un Livre de Mémoire'),
  ('mb_page.eyebrow', 'fr', 'Livre de Mémoire'),
  ('mb_page.hero_title', 'fr', 'Tout ce qu''un aidant doit savoir — en un seul endroit'),
  ('mb_page.hero_body', 'fr', 'Quand un nouvel aidant arrive, il ne devrait pas avoir à deviner. Le Livre de Mémoire capture qui est votre proche, qui appeler, quoi surveiller et ce qui lui apporte du réconfort — partagé instantanément avec toute votre équipe de soins.'),
  ('mb_page.hero_cta_primary', 'fr', 'Créer votre Livre de Mémoire'),
  ('mb_page.hero_cta_secondary', 'fr', 'Se Connecter'),
  ('mb_page.mock_title', 'fr', 'Découvrez à quoi ressemble le Livre de Mémoire'),
  ('mb_page.mock_subtitle', 'fr', 'Un profil de soins vivant que chaque membre de votre équipe peut consulter dès qu''il rejoint.'),
  ('mb_page.mock_book_title', 'fr', 'Livre de Mémoire'),
  ('mb_page.mock_tab_overview', 'fr', 'Aperçu'),
  ('mb_page.mock_tab_identity', 'fr', 'Identité'),
  ('mb_page.mock_tab_contacts', 'fr', 'Contacts'),
  ('mb_page.mock_tab_medical', 'fr', 'Médical'),
  ('mb_page.mock_tab_prefs', 'fr', 'Goûts et Dégoûts'),
  ('mb_page.mock_identity_heading', 'fr', 'Identité et Profil'),
  ('mb_page.mock_identity_sub', 'fr', 'Informations personnelles de Marguerite H.'),
  ('mb_page.mock_edit_btn', 'fr', 'Modifier'),
  ('mb_page.mock_field_preferred_name', 'fr', 'Prénom Préféré'),
  ('mb_page.mock_field_address', 'fr', 'Comment s''adresser'),
  ('mb_page.mock_field_birthplace', 'fr', 'Lieu de Naissance'),
  ('mb_page.mock_field_rel_status', 'fr', 'Situation Familiale'),
  ('mb_page.mock_field_cultural', 'fr', 'Origine Culturelle'),
  ('mb_page.mock_field_language', 'fr', 'Préférences Linguistiques'),
  ('mb_page.mock_field_about', 'fr', 'À Propos de Moi'),
  ('mb_page.mock_about_text', 'fr', 'Marguerite a passé 30 ans comme institutrice à Édimbourg avant d''émigrer avec son défunt mari Jacques. Elle a un sens de l''humour chaleureux et pince-sans-rire, et un profond amour pour les mots croisés, une bonne tasse de thé et les histoires de ses petits-enfants.'),
  ('mb_page.mock_progress_label', 'fr', 'Progression du Livre de Mémoire'),
  ('mb_page.mock_sections', 'fr', 'sections complètes'),
  ('mb_page.benefits_title', 'fr', 'Pourquoi les familles font confiance au Livre de Mémoire'),
  ('mb_page.benefits_subtitle', 'fr', 'Les équipes de soins fonctionnent mieux quand tout le monde a les mêmes informations dès le premier jour.'),
  ('mb_page.benefit1_title', 'fr', 'Contexte de soins immédiat'),
  ('mb_page.benefit1_body', 'fr', 'Tout nouvel aidant — un remplaçant, un frère en visite de l''étranger — arrive avec tout ce dont il a besoin pour prodiguer de bons soins dès le premier instant.'),
  ('mb_page.benefit2_title', 'fr', 'Fini de chercher des numéros'),
  ('mb_page.benefit2_body', 'fr', 'Chaque membre de la famille, médecin et contact d''urgence en un seul endroit. Trouvez la bonne personne en quelques secondes, pas en minutes.'),
  ('mb_page.benefit3_title', 'fr', 'Transmissions plus sûres'),
  ('mb_page.benefit3_body', 'fr', 'Notes médicales, allergies et considérations de soins toujours à portée de main. Des transitions informées signifient moins de lacunes et moins de risques.'),
  ('mb_page.benefit4_title', 'fr', 'Dignité personnelle'),
  ('mb_page.benefit4_body', 'fr', 'Au-delà des faits cliniques, le Livre de Mémoire capture la personne — son histoire, ses préférences, ce qui lui apporte de la joie. Les soins deviennent plus que l''accomplissement de tâches.'),
  ('mb_page.features_title', 'fr', 'Quatre sections. Une image complète.'),
  ('mb_page.features_subtitle', 'fr', 'Chaque section est conçue autour de moments réels de soins — transmissions, urgences, nouveaux membres d''équipe et soins quotidiens.'),
  ('mb_page.feat_identity_title', 'fr', 'Identité et Profil Personnel'),
  ('mb_page.feat_identity_body', 'fr', 'Capturez qui est votre proche — pas seulement son nom, mais son histoire. Cette section aide chaque aidant à se connecter avec la personne derrière le plan de soins.'),
  ('mb_page.feat_identity_f1', 'fr', 'Prénom préféré et comment il aime être adressé'),
  ('mb_page.feat_identity_f2', 'fr', 'Lieu de naissance et origine culturelle'),
  ('mb_page.feat_identity_f3', 'fr', 'Situation familiale'),
  ('mb_page.feat_identity_f4', 'fr', 'Préférences linguistiques et de communication'),
  ('mb_page.feat_identity_f5', 'fr', 'Résumé personnel — dans ses propres mots'),
  ('mb_page.feat_contacts_title', 'fr', 'Réseau de Soins et Contacts'),
  ('mb_page.feat_contacts_body', 'fr', 'Stockez chaque personne dans le réseau de soutien de votre proche — famille, médecins, spécialistes et contacts d''urgence — chacun avec son rôle, téléphone, email et notes.'),
  ('mb_page.feat_contacts_f1', 'fr', 'Membres de la famille et leur relation'),
  ('mb_page.feat_contacts_f2', 'fr', 'Contacts du médecin généraliste et des spécialistes'),
  ('mb_page.feat_contacts_f3', 'fr', 'Voisins et soutien communautaire'),
  ('mb_page.feat_contacts_f4', 'fr', 'Étiquettes de rôle : aidant principal, urgence, médical, autre'),
  ('mb_page.feat_medical_title', 'fr', 'Contexte Médical'),
  ('mb_page.feat_medical_body', 'fr', 'Pas un dossier clinique — une référence pratique pour aidants. Documentez ce que les aidants à domicile et familiaux ont réellement besoin de savoir pour prodiguer des soins sûrs et confiants.'),
  ('mb_page.feat_medical_f1', 'fr', 'Conditions principales et diagnostics'),
  ('mb_page.feat_medical_f2', 'fr', 'Allergies (alimentaires, médicamenteuses, environnementales)'),
  ('mb_page.feat_medical_f3', 'fr', 'Notes sur l''audition et la vision'),
  ('mb_page.feat_medical_f4', 'fr', 'Médicaments actuels et notes d''administration'),
  ('mb_page.feat_medical_f5', 'fr', 'Autres considérations de santé pour les aidants'),
  ('mb_page.feat_prefs_title', 'fr', 'Goûts, Dégoûts et Réconforts'),
  ('mb_page.feat_prefs_body', 'fr', 'Les détails qui transforment les soins de fonctionnels à personnels. Savoir ce qui apaise, ce qu''il faut éviter et ce qui provoque un vrai sourire rend chaque interaction meilleure.'),
  ('mb_page.feat_prefs_f1', 'fr', 'Activités, sujets et expériences qu''ils apprécient'),
  ('mb_page.feat_prefs_f2', 'fr', 'Préférences alimentaires et choses à éviter'),
  ('mb_page.feat_prefs_f3', 'fr', 'Préférences musicales et sujets de conversation favoris'),
  ('mb_page.feat_prefs_f4', 'fr', 'Ce qui les réconforte quand ils sont contrariés'),
  ('mb_page.feat_prefs_f5', 'fr', 'Préférences sensorielles et déclencheurs de détresse'),
  ('mb_page.access_title', 'fr', 'Conçu pour l''équipe. Visible par tous.'),
  ('mb_page.access_body', 'fr', 'Le propriétaire de l''équipe crée le Livre de Mémoire. Chaque aidant que vous invitez — membres de la famille, travailleurs à domicile ou personnes de soutien — peut le voir dès qu''il rejoint, sans configuration requise.'),
  ('mb_page.access_cta', 'fr', 'Créer votre Compte Gratuit'),
  ('mb_page.access_plans', 'fr', 'Voir les Plans et Tarifs'),
  ('mb_page.personas_title', 'fr', 'Qui bénéficie du Livre de Mémoire'),
  ('mb_page.personas_subtitle', 'fr', 'De l''aidant de nuit qui arrive pour la première fois au frère qui vérifie depuis l''étranger.'),
  ('mb_page.persona1_title', 'fr', 'L''aidant remplaçant de nuit'),
  ('mb_page.persona1_quote', 'fr', '"J''appréhendais de remplacer pour une famille que je ne connaissais pas. Maintenant je consulte le Livre de Mémoire avant d''arriver."'),
  ('mb_page.persona1_b1', 'fr', 'Connaît les routines préférées et les réconforts au coucher avant d''entrer'),
  ('mb_page.persona1_b2', 'fr', 'Peut trouver les contacts d''urgence sans réveiller personne'),
  ('mb_page.persona1_b3', 'fr', 'Comprend les besoins en médicaments dès la première nuit'),
  ('mb_page.persona2_title', 'fr', 'Le frère qui revient de l''étranger'),
  ('mb_page.persona2_quote', 'fr', '"Je rends visite deux fois par an et je me sens comme un étranger. Le Livre de Mémoire comble cet écart."'),
  ('mb_page.persona2_b1', 'fr', 'Se met à jour sur le contexte médical sans un long briefing familial'),
  ('mb_page.persona2_b2', 'fr', 'Sait ce que Maman apprécie maintenant versus il y a un an'),
  ('mb_page.persona2_b3', 'fr', 'Peut intervenir et aider avec confiance dès le premier jour'),
  ('mb_page.persona3_title', 'fr', 'L''aidant principal'),
  ('mb_page.persona3_quote', 'fr', '"Je suis la banque de mémoire. Le Livre de Mémoire signifie que je n''ai pas à tout expliquer à chaque fois."'),
  ('mb_page.persona3_b1', 'fr', 'Documente tout une fois — pas une douzaine de fois'),
  ('mb_page.persona3_b2', 'fr', 'Partage la charge des soins sans perdre le contrôle de la précision'),
  ('mb_page.persona3_b3', 'fr', 'Réduit la charge émotionnelle de la communication constante'),
  ('mb_page.persona4_title', 'fr', 'Le médecin généraliste ou infirmier communautaire'),
  ('mb_page.persona4_quote', 'fr', '"Les familles qui arrivent organisées nous aident à fournir de meilleurs soins."'),
  ('mb_page.persona4_b1', 'fr', 'Les aidants arrivent aux rendez-vous avec des notes médicales claires et actuelles'),
  ('mb_page.persona4_b2', 'fr', 'Les allergies et conditions sont documentées, pas supposées'),
  ('mb_page.persona4_b3', 'fr', 'Les contacts sont disponibles pour des conversations de soins coordonnées'),
  ('mb_page.faq_title', 'fr', 'Questions Fréquemment Posées'),
  ('mb_page.faq_subtitle', 'fr', 'Questions courantes sur la fonctionnalité Livre de Mémoire.'),
  ('mb_page.faq1_q', 'fr', 'Qu''est-ce que le Livre de Mémoire et qui peut le voir ?'),
  ('mb_page.faq1_a', 'fr', 'Le Livre de Mémoire est un profil de soins structuré pour votre proche, couvrant l''identité, les contacts, le contexte médical et les préférences personnelles. Il fait partie de votre plan Family Circle CarerView. Le propriétaire de l''équipe le crée et le met à jour. Chaque membre de l''équipe que vous invitez peut voir le Livre de Mémoire complet dès qu''il rejoint — aucune configuration supplémentaire requise.'),
  ('mb_page.faq2_q', 'fr', 'Ai-je besoin du plan Family Circle pour utiliser le Livre de Mémoire ?'),
  ('mb_page.faq2_a', 'fr', 'Oui. Le Livre de Mémoire est une fonctionnalité d''équipe disponible sur le plan Family Circle. Il est conçu pour être partagé — donc il est plus utile quand vous avez au moins un autre aidant ou membre de la famille dans votre équipe qui bénéficie de voir les mêmes informations que vous avez enregistrées.'),
  ('mb_page.faq3_q', 'fr', 'Les membres de l''équipe peuvent-ils modifier le Livre de Mémoire ?'),
  ('mb_page.faq3_a', 'fr', 'Actuellement, seul le propriétaire de l''équipe peut créer et modifier les entrées du Livre de Mémoire. Tous les autres membres de l''équipe ont un accès en lecture seule. Cela garantit que le Livre de Mémoire reste précis et cohérent, avec une personne responsable de le maintenir à jour.'),
  ('mb_page.faq4_q', 'fr', 'Le Livre de Mémoire est-il un dossier médical ?'),
  ('mb_page.faq4_a', 'fr', 'Non. Le Livre de Mémoire est une référence pratique pour aidants — pas un document clinique. Il capture des informations qui aident les aidants à fournir des soins sûrs, informés et personnels. Pour les dossiers médicaux formels, veuillez vous référer aux prestataires de soins de santé de votre proche.'),
  ('mb_page.faq5_q', 'fr', 'Que se passe-t-il si j''oublie de remplir une section ?'),
  ('mb_page.faq5_a', 'fr', 'Le Livre de Mémoire fonctionne avec ce que vous ajoutez. Les sections incomplètes affichent un statut clair pour que le propriétaire de l''équipe sache ce qui est encore nécessaire. Vous pouvez le construire progressivement — même un Livre de Mémoire partiellement complété apporte une valeur significative aux aidants entrants.'),
  ('mb_page.faq6_q', 'fr', 'Les informations de mon proche sont-elles privées et sécurisées ?'),
  ('mb_page.faq6_a', 'fr', 'Oui. Le Livre de Mémoire n''est visible que par les membres de votre équipe de soins — des personnes que vous avez explicitement invitées. Il est stocké en toute sécurité sur une infrastructure chiffrée. CarerView ne partage jamais vos données avec des tiers et vous conservez la pleine propriété de toutes les informations que vous saisissez.'),
  ('mb_page.faq7_q', 'fr', 'Le Livre de Mémoire va-t-il évoluer avec le temps ?'),
  ('mb_page.faq7_a', 'fr', 'Oui. Le Livre de Mémoire actuel couvre les quatre sections principales : Identité, Contacts, Médical et Préférences. Les mises à jour futures ajouteront des routines de Vie Quotidienne, des Repas, des Activités, une section Comportement & Sécurité, un Journal personnel et un Journal des Changements. Les entrées existantes sont préservées lors de toutes les mises à jour.'),
  ('mb_page.cta_title', 'fr', 'Commencez à créer le Livre de Mémoire de votre proche aujourd''hui'),
  ('mb_page.cta_body', 'fr', 'Créez un compte gratuit et explorez CarerView — ou passez au plan Family Circle pour débloquer le Livre de Mémoire et le partager avec votre équipe de soins.')
INSERT INTO ui_translations (key, locale, value) VALUES
  ('nav.memory_book', 'de', 'Warum Ihre Familie ein Erinnerungsbuch braucht'),
  ('mb_page.eyebrow', 'de', 'Erinnerungsbuch'),
  ('mb_page.hero_title', 'de', 'Alles, was ein Pflegeperson wissen muss — an einem Ort'),
  ('mb_page.hero_body', 'de', 'Wenn eine neue Pflegeperson ankommt, sollte sie nicht raten müssen. Das Erinnerungsbuch hält fest, wer Ihr geliebter Mensch ist, wen man anrufen soll, worauf man achten muss und was ihm Trost bringt — sofort mit allen in Ihrem Pflegeteam geteilt.'),
  ('mb_page.hero_cta_primary', 'de', 'Ihr Erinnerungsbuch erstellen'),
  ('mb_page.hero_cta_secondary', 'de', 'Anmelden'),
  ('mb_page.mock_title', 'de', 'Sehen Sie, wie das Erinnerungsbuch aussieht'),
  ('mb_page.mock_subtitle', 'de', 'Ein lebendiges Pflegeprofil, das jedes Mitglied Ihres Teams sehen kann, sobald es beitritt.'),
  ('mb_page.mock_book_title', 'de', 'Erinnerungsbuch'),
  ('mb_page.mock_tab_overview', 'de', 'Übersicht'),
  ('mb_page.mock_tab_identity', 'de', 'Identität'),
  ('mb_page.mock_tab_contacts', 'de', 'Kontakte'),
  ('mb_page.mock_tab_medical', 'de', 'Medizinisch'),
  ('mb_page.mock_tab_prefs', 'de', 'Vorlieben & Abneigungen'),
  ('mb_page.mock_identity_heading', 'de', 'Identität & Profil'),
  ('mb_page.mock_identity_sub', 'de', 'Persönliche Daten von Margarete H.'),
  ('mb_page.mock_edit_btn', 'de', 'Bearbeiten'),
  ('mb_page.mock_field_preferred_name', 'de', 'Bevorzugter Name'),
  ('mb_page.mock_field_address', 'de', 'Anrede'),
  ('mb_page.mock_field_birthplace', 'de', 'Geburtsort'),
  ('mb_page.mock_field_rel_status', 'de', 'Familienstand'),
  ('mb_page.mock_field_cultural', 'de', 'Kultureller Hintergrund'),
  ('mb_page.mock_field_language', 'de', 'Sprachpräferenzen'),
  ('mb_page.mock_field_about', 'de', 'Über mich'),
  ('mb_page.mock_about_text', 'de', 'Margarete war 30 Jahre lang Lehrerin in Edinburgh, bevor sie mit ihrem verstorbenen Mann Jakob auswanderte. Sie hat einen warmen, trockenen Humor und liebt Kreuzworträtsel, eine gute Tasse Tee und Geschichten über ihre Enkelkinder.'),
  ('mb_page.mock_progress_label', 'de', 'Fortschritt des Erinnerungsbuchs'),
  ('mb_page.mock_sections', 'de', 'Abschnitte vollständig'),
  ('mb_page.benefits_title', 'de', 'Warum Familien auf das Erinnerungsbuch vertrauen'),
  ('mb_page.benefits_subtitle', 'de', 'Pflegeteams arbeiten besser, wenn alle von Anfang an dieselben Informationen haben.'),
  ('mb_page.benefit1_title', 'de', 'Sofortiger Pflegekontext'),
  ('mb_page.benefit1_body', 'de', 'Jede neue Pflegeperson — ein Vertretungshelfer, ein Geschwister aus dem Ausland — kommt mit allem an, was nötig ist, um vom ersten Moment an gute Pflege zu leisten.'),
  ('mb_page.benefit2_title', 'de', 'Kein Suchen nach Nummern mehr'),
  ('mb_page.benefit2_body', 'de', 'Jedes Familienmitglied, jeder Arzt und jeder Notfallkontakt an einem Ort. Finden Sie die richtige Person in Sekunden, nicht in Minuten.'),
  ('mb_page.benefit3_title', 'de', 'Sicherere Übergaben'),
  ('mb_page.benefit3_body', 'de', 'Medizinische Notizen, Allergien und Pflegeüberlegungen immer zur Hand. Informierte Übergaben bedeuten weniger Lücken und weniger Risiken.'),
  ('mb_page.benefit4_title', 'de', 'Persönliche Würde'),
  ('mb_page.benefit4_body', 'de', 'Über klinische Fakten hinaus erfasst das Erinnerungsbuch die Person — ihre Geschichte, ihre Vorlieben, was ihr Freude bringt. Pflege wird mehr als nur Aufgaben erledigen.'),
  ('mb_page.features_title', 'de', 'Vier Abschnitte. Ein vollständiges Bild.'),
  ('mb_page.features_subtitle', 'de', 'Jeder Abschnitt ist auf echte Pflegemomente ausgerichtet — Übergaben, Notfälle, neue Teammitglieder und alltägliche Pflege.'),
  ('mb_page.feat_identity_title', 'de', 'Identität & Persönliches Profil'),
  ('mb_page.feat_identity_body', 'de', 'Erfassen Sie, wer Ihr geliebter Mensch ist — nicht nur seinen Namen, sondern seine Geschichte. Dieser Abschnitt hilft jeder Pflegeperson, sich mit der Person hinter dem Pflegeplan zu verbinden.'),
  ('mb_page.feat_identity_f1', 'de', 'Bevorzugter Name und bevorzugte Anrede'),
  ('mb_page.feat_identity_f2', 'de', 'Geburtsort und kultureller Hintergrund'),
  ('mb_page.feat_identity_f3', 'de', 'Familienstand'),
  ('mb_page.feat_identity_f4', 'de', 'Sprach- und Kommunikationspräferenzen'),
  ('mb_page.feat_identity_f5', 'de', 'Persönliche Zusammenfassung — in eigenen Worten'),
  ('mb_page.feat_contacts_title', 'de', 'Pflegenetzwerk & Kontakte'),
  ('mb_page.feat_contacts_body', 'de', 'Speichern Sie jede Person im Unterstützungsnetzwerk Ihres geliebten Menschen — Familie, Ärzte, Spezialisten und Notfallkontakte — jeder mit Rolle, Telefon, E-Mail und Notizen.'),
  ('mb_page.feat_contacts_f1', 'de', 'Familienmitglieder und ihre Beziehung'),
  ('mb_page.feat_contacts_f2', 'de', 'Hausarzt- und Spezialistenkontakte'),
  ('mb_page.feat_contacts_f3', 'de', 'Nachbarn und Gemeinschaftsunterstützung'),
  ('mb_page.feat_contacts_f4', 'de', 'Rollenetiketten: Hauptpflegeperson, Notfall, medizinisch, andere'),
  ('mb_page.feat_medical_title', 'de', 'Medizinischer Kontext'),
  ('mb_page.feat_medical_body', 'de', 'Keine klinische Akte — eine praktische Pflegepersonenreferenz. Dokumentieren Sie, was häusliche und familiäre Pflegepersonen wirklich wissen müssen, um sichere, selbstbewusste Pflege zu leisten.'),
  ('mb_page.feat_medical_f1', 'de', 'Haupterkrankungen und Diagnosen'),
  ('mb_page.feat_medical_f2', 'de', 'Allergien (Nahrungsmittel, Medikamente, Umwelt)'),
  ('mb_page.feat_medical_f3', 'de', 'Hör- und Sehnotizen'),
  ('mb_page.feat_medical_f4', 'de', 'Aktuelle Medikamente und Verabreichungshinweise'),
  ('mb_page.feat_medical_f5', 'de', 'Andere Gesundheitsüberlegungen für Pflegepersonen'),
  ('mb_page.feat_prefs_title', 'de', 'Vorlieben, Abneigungen & Trost'),
  ('mb_page.feat_prefs_body', 'de', 'Die Details, die Pflege von funktional zu persönlich machen. Zu wissen, was beruhigt, was zu vermeiden ist und was ein echtes Lächeln hervorruft, macht jede Interaktion besser.'),
  ('mb_page.feat_prefs_f1', 'de', 'Aktivitäten, Themen und Erfahrungen, die sie genießen'),
  ('mb_page.feat_prefs_f2', 'de', 'Nahrungsmittelpräferenzen und zu vermeidende Dinge'),
  ('mb_page.feat_prefs_f3', 'de', 'Musikpräferenzen und Lieblingsgesprächsthemen'),
  ('mb_page.feat_prefs_f4', 'de', 'Was sie tröstet, wenn sie aufgewühlt sind'),
  ('mb_page.feat_prefs_f5', 'de', 'Sensorische Präferenzen und Belastungsauslöser'),
  ('mb_page.access_title', 'de', 'Für das Team gebaut. Für alle sichtbar.'),
  ('mb_page.access_body', 'de', 'Der Teambesitzer erstellt das Erinnerungsbuch. Jede Pflegeperson, die Sie einladen — Familienmitglieder, häusliche Helfer oder Unterstützungspersonen — kann es sehen, sobald sie beitritt, ohne Einrichtung erforderlich.'),
  ('mb_page.access_cta', 'de', 'Kostenloses Konto erstellen'),
  ('mb_page.access_plans', 'de', 'Pläne & Preise ansehen'),
  ('mb_page.personas_title', 'de', 'Wer vom Erinnerungsbuch profitiert'),
  ('mb_page.personas_subtitle', 'de', 'Vom Nachtpflegehelfer, der zum ersten Mal ankommt, bis zum Geschwister, das aus dem Ausland nachfragt.'),
  ('mb_page.persona1_title', 'de', 'Der nächtliche Vertretungshelfer'),
  ('mb_page.persona1_quote', 'de', '"Früher habe ich davor gebangt, für eine Familie einzuspringen, die ich nicht kannte. Jetzt schaue ich vor der Ankunft ins Erinnerungsbuch."'),
  ('mb_page.persona1_b1', 'de', 'Kennt bevorzugte Routinen und Schlafenszeit-Tröster vor dem Betreten'),
  ('mb_page.persona1_b2', 'de', 'Kann Notfallkontakte finden, ohne jemanden aufzuwecken'),
  ('mb_page.persona1_b3', 'de', 'Versteht den Medikamentenbedarf ab der ersten Nacht'),
  ('mb_page.persona2_title', 'de', 'Das Geschwister, das aus dem Ausland zurückkehrt'),
  ('mb_page.persona2_quote', 'de', '"Ich besuche zweimal im Jahr und fühle mich wie ein Fremder. Das Erinnerungsbuch schließt diese Lücke."'),
  ('mb_page.persona2_b1', 'de', 'Holt den medizinischen Kontext auf ohne ein langes Familienbriefing'),
  ('mb_page.persona2_b2', 'de', 'Weiß, was Mama jetzt genießt, im Vergleich zu vor einem Jahr'),
  ('mb_page.persona2_b3', 'de', 'Kann selbstbewusst von Tag eins an einspringen und helfen'),
  ('mb_page.persona3_title', 'de', 'Die Hauptpflegeperson'),
  ('mb_page.persona3_quote', 'de', '"Ich bin die Gedächtnisbank. Das Erinnerungsbuch bedeutet, dass ich nicht jedes Mal alles erklären muss."'),
  ('mb_page.persona3_b1', 'de', 'Dokumentiert alles einmal — nicht ein Dutzend Mal'),
  ('mb_page.persona3_b2', 'de', 'Teilt die Pflegelast, ohne die Kontrolle über Genauigkeit zu verlieren'),
  ('mb_page.persona3_b3', 'de', 'Reduziert die emotionale Last der ständigen Kommunikation'),
  ('mb_page.persona4_title', 'de', 'Der Hausarzt oder Gemeindepfleger'),
  ('mb_page.persona4_quote', 'de', '"Familien, die organisiert ankommen, helfen uns, bessere Pflege zu leisten."'),
  ('mb_page.persona4_b1', 'de', 'Pflegepersonen kommen zu Terminen mit klaren, aktuellen Notizen'),
  ('mb_page.persona4_b2', 'de', 'Allergien und Erkrankungen sind dokumentiert, nicht geraten'),
  ('mb_page.persona4_b3', 'de', 'Kontakte sind für koordinierte Pflegegespräche verfügbar'),
  ('mb_page.faq_title', 'de', 'Häufig gestellte Fragen'),
  ('mb_page.faq_subtitle', 'de', 'Häufige Fragen zur Erinnerungsbuch-Funktion.'),
  ('mb_page.faq1_q', 'de', 'Was ist das Erinnerungsbuch und wer kann es sehen?'),
  ('mb_page.faq1_a', 'de', 'Das Erinnerungsbuch ist ein strukturiertes Pflegeprofil für Ihren geliebten Menschen, das Identität, Kontakte, medizinischen Kontext und persönliche Präferenzen abdeckt. Es ist Teil Ihres CarerView Family Circle Plans. Der Teambesitzer erstellt und aktualisiert es. Jedes Teammitglied, das Sie einladen, kann das vollständige Erinnerungsbuch sehen, sobald es beitritt — ohne zusätzliche Einrichtung.'),
  ('mb_page.faq2_q', 'de', 'Brauche ich den Family Circle Plan für das Erinnerungsbuch?'),
  ('mb_page.faq2_a', 'de', 'Ja. Das Erinnerungsbuch ist eine Teamfunktion, die im Family Circle Plan verfügbar ist. Es ist zum Teilen konzipiert — daher macht es am meisten Sinn, wenn Sie mindestens eine weitere Pflegeperson oder ein Familienmitglied in Ihrem Team haben, das davon profitiert, dieselben Informationen zu sehen, die Sie aufgezeichnet haben.'),
  ('mb_page.faq3_q', 'de', 'Können Teammitglieder das Erinnerungsbuch bearbeiten?'),
  ('mb_page.faq3_a', 'de', 'Derzeit kann nur der Teambesitzer Einträge im Erinnerungsbuch erstellen und bearbeiten. Alle anderen Teammitglieder haben nur Lesezugriff. Dies stellt sicher, dass das Erinnerungsbuch genau und konsistent bleibt, mit einer Person, die für die Aktualisierung verantwortlich ist.'),
  ('mb_page.faq4_q', 'de', 'Ist das Erinnerungsbuch eine Krankenakte?'),
  ('mb_page.faq4_a', 'de', 'Nein. Das Erinnerungsbuch ist eine praktische Pflegepersonenreferenz — kein klinisches Dokument. Es erfasst Informationen, die Pflegepersonen dabei helfen, sichere, informierte und persönliche Pflege zu leisten. Für formelle Krankenakten wenden Sie sich bitte an die Gesundheitsversorger Ihres geliebten Menschen.'),
  ('mb_page.faq5_q', 'de', 'Was passiert, wenn ich vergesse, einen Abschnitt auszufüllen?'),
  ('mb_page.faq5_a', 'de', 'Das Erinnerungsbuch funktioniert mit dem, was Sie hinzufügen. Unvollständige Abschnitte zeigen einen klaren Status, damit der Teambesitzer weiß, was noch benötigt wird. Sie können es schrittweise aufbauen — auch ein teilweise ausgefülltes Erinnerungsbuch bietet eingehenden Pflegepersonen erheblichen Mehrwert.'),
  ('mb_page.faq6_q', 'de', 'Sind die Informationen meines geliebten Menschen privat und sicher?'),
  ('mb_page.faq6_a', 'de', 'Ja. Das Erinnerungsbuch ist nur für Mitglieder Ihres Pflegeteams sichtbar — Personen, die Sie ausdrücklich eingeladen haben. Es wird sicher auf verschlüsselter Infrastruktur gespeichert. CarerView gibt Ihre Daten niemals an Dritte weiter und Sie behalten das volle Eigentum an allen Informationen, die Sie eingeben.'),
  ('mb_page.faq7_q', 'de', 'Wird das Erinnerungsbuch mit der Zeit wachsen?'),
  ('mb_page.faq7_a', 'de', 'Ja. Das aktuelle Erinnerungsbuch umfasst die vier Kernabschnitte: Identität, Kontakte, Medizinisch und Präferenzen. Zukünftige Updates werden Alltagsroutinen, Mahlzeiten, Aktivitäten, einen Verhaltens- & Sicherheitsabschnitt, ein persönliches Tagebuch und ein Änderungsprotokoll hinzufügen. Bestehende Einträge bleiben bei allen Updates erhalten.'),
  ('mb_page.cta_title', 'de', 'Beginnen Sie noch heute, das Erinnerungsbuch Ihres geliebten Menschen zu erstellen'),
  ('mb_page.cta_body', 'de', 'Erstellen Sie ein kostenloses Konto und erkunden Sie CarerView — oder upgraden Sie auf den Family Circle Plan, um das Erinnerungsbuch freizuschalten und es mit Ihrem Pflegeteam zu teilen.')
